import asyncioasyncio.set_event_loop(asyncio.new_event_loop())from telethon import TelegramClient, eventsimport MetaTrader5 as mt5import refrom datetime import datetimeprint("SCRIPT STARTED")# TELEGRAM APIapi_id = 32983741api_hash = "2d2533be9b3326858ba5bcdd71f107fe"channels = [    "THEPIPSROOM",    "Goldvsusa_doller",    "rdnamemax"]# SETTINGSlot_size = 0.01symbol = "XAUUSD"   # ⚠️ change if needed (e.g. XAUUSDm)tp1_distance = 12.0max_spread_points = 500magic_number = 555client = TelegramClient("session_main", api_id, api_hash)processed_signals = set()tp1_price = Nonedef log(text):    time = datetime.now().strftime("%H:%M:%S")    print(f"[{time}] {text}")def connect_mt5():    log("Connecting to MT5...")    if not mt5.initialize():        log("❌ MT5 INIT FAILED")        return False    acc = mt5.account_info()    if acc is None:        log("❌ NO ACCOUNT")        return False    log(f"✅ Connected: {acc.login}")    return Truedef spread_ok():    tick = mt5.symbol_info_tick(symbol)    info = mt5.symbol_info(symbol)    if not tick or not info:        log("❌ No tick data")        return False    spread = (tick.ask - tick.bid) / info.point    log(f"Spread: {spread}")    return spread <= max_spread_pointsdef extract_order_type(msg):    if "BUY" in msg:        return "BUY"    if "SELL" in msg:        return "SELL"    return Nonedef extract_entries(msg):    nums = re.findall(r"\d+(?:\.\d+)?", msg)    if len(nums) >= 2:        return float(nums[0]), float(nums[1])    return None, Nonedef extract_sl(msg):    m = re.search(r"SL[: ]*(\d+(?:\.\d+)?)", msg)    return float(m.group(1)) if m else Nonedef extract_tp2(msg):    m = re.search(r"TP2[: ]*(\d+(?:\.\d+)?)", msg)    if m:        return float(m.group(1))    tps = re.findall(r"TP[: ]*(\d+(?:\.\d+)?)", msg)    if len(tps) >= 2:        return float(tps[1])    return Nonedef place_order(order_type, entry, sl, tp):    tick = mt5.symbol_info_tick(symbol)    if not tick:        log("❌ No tick for order")        return    if order_type == "BUY":        order = mt5.ORDER_TYPE_BUY_LIMIT if entry <= tick.ask else mt5.ORDER_TYPE_BUY_STOP    else:        order = mt5.ORDER_TYPE_SELL_LIMIT if entry >= tick.bid else mt5.ORDER_TYPE_SELL_STOP    log(f"🚀 Order: {order_type} | Entry={entry} | SL={sl} | TP={tp}")    result = mt5.order_send({        "action": mt5.TRADE_ACTION_PENDING,        "symbol": symbol,        "volume": lot_size,        "type": order,        "price": entry,        "sl": sl,        "tp": tp,        "deviation": 20,        "magic": magic_number,        "type_time": mt5.ORDER_TIME_GTC,        "type_filling": mt5.ORDER_FILLING_RETURN,    })    log(f"📊 Result: {result}")@client.on(events.NewMessage(chats=channels))async def handler(event):    global tp1_price    msg = event.raw_text.upper().strip()    log(f"\n📩 SIGNAL:\n{msg}")    if hash(msg) in processed_signals:        log("Duplicate skipped")        return    processed_signals.add(hash(msg))    if "CLOSE" in msg:        log("Close command received")        return    if not spread_ok():        log("Blocked by spread")        return    order_type = extract_order_type(msg)    if not order_type:        log("No BUY/SELL found")        return    entry1, entry2 = extract_entries(msg)    if entry1 is None or entry2 is None:        log("No entries found")        return    sl = extract_sl(msg)    if sl is None:        log("No SL found")        return    tp2 = extract_tp2(msg)    if tp2 is None:        log("No TP2 found")        return    tp1 = entry1 + tp1_distance if order_type == "BUY" else entry1 - tp1_distance    tp1_price = tp1    log(f"Parsed → {order_type} | {entry1}, {entry2} | SL {sl} | TP1 {tp1} | TP2 {tp2}")    place_order(order_type, entry1, sl, tp1)    place_order(order_type, entry2, sl, tp2)async def main():    print("ENTERED MAIN")    if not connect_mt5():        input("Fix MT5 and press Enter...")        return    await client.start()    log("🔥 BOT RUNNING - WAITING FOR SIGNALS")    await client.run_until_disconnected()if __name__ == "__main__":    asyncio.run(main())